def seed():
    for s in stadiums_data:
        data = {k:v for k,v in s.items() if k != "id"}
        set_document("stadiums", s["id"], data)
    set_document("config", "matchday", config_data)
    for lang in languages_data:
        data = {k:v for k,v in lang.items() if k != "code"}
        db.collection("languages").document(lang["code"]).set(data)
    print("Seed complete.")

if __name__ == "__main__":
    seed()
